parameters.jsCode:
const trackToText = (track) => {
  return track.transcript.map(t => t.text.replace(/[\r\n]/gm, '')).join(' ');
}
return $input.all().reduce((acc, cur) => ({...acc, [cur.json.id]: trackToText(cur.json.tracks[0])}), {})

return {
  // add a maximum of 50 ids here
  ids: $input.first().json.IDs.split(',')
}

